Rules.InvariantScript:
Set(
    varSelectedIncident,
    First(
        Filter(
            EmergencyIncidents,
            Status.Value = "New" && Coalesce('Support Requested', false) = false
        )
    )
)

Assert(
    CountRows(
        Filter(
            galIncidentOverview.AllItems,
            'Incident ID' = varSelectedIncident.'Incident ID'
        )
    ) = 0
)
